// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! Property tc_req_01 -- Pre-Assert and Next-Assert VCs for every schema transition.
//! Each proof fn has an empty body: Verus discharges `requires ==> ensures`
//! via SMT; add proof hints in the body if a VC does not discharge.

#![allow(non_snake_case)]
#![allow(unused_variables)]
#![allow(unused_imports)]

use vstd::prelude::*;

use crate::assertions::*;
use crate::tc_req_01::assertions::*;
use crate::contracts::*;
use crate::system_state::SystemState;
use crate::write_frames::*;

verus! {

/** VC[1]: Pre-Assert -- START |- SENSOR compute assumes */
pub proof fn vc_pre_assert_sensor(st: SystemState)
  requires
    sys_assert_tc_req_01_START(st),
  ensures
    true /* no assertions at out-places */,
{}

/** VC[2]: Next-Assert (task) -- START + frames + SENSOR postcondition |- after_sensor */
pub proof fn vc_next_assert_task_sensor(pre: SystemState, post: SystemState)
  requires
    sys_assert_tc_req_01_START(pre),
    sensor_local_write_frame(pre, post),
    sensor_global_write_frame(pre, post),
    sensor::integration_spec_Sensor_Temperature_Range_guarantee(post.sensedTemp),
  ensures
    sys_assert_tc_req_01_after_sensor(post),
{}

/** VC[3]: Pre-Assert -- after_sensor |- CONTROL compute assumes */
pub proof fn vc_pre_assert_control(st: SystemState)
  requires
    sys_assert_tc_req_01_after_sensor(st),
  ensures
    control::compute_spec_a1_assume(st.sv_currentFanState, st.sv_currentSetPoint, st.sv_fanError, st.sv_latestTemp),
    control::compute_spec_a2_assume(st.sv_currentFanState, st.sv_currentSetPoint, st.sv_fanError, st.sv_latestTemp),
{}

/** VC[4]: Next-Assert (task) -- after_sensor + frames + CONTROL postcondition |- after_control */
pub proof fn vc_next_assert_task_control(pre: SystemState, post: SystemState)
  requires
    sys_assert_tc_req_01_after_sensor(pre),
    control_local_write_frame(pre, post),
    control_global_write_frame(pre, post),
    control::compute_spec_errorState_guarantee(pre.sv_currentFanState, post.sv_currentFanState, post.sv_fanError, post.fanCmd),
    control::compute_spec_TC_Req_01_guarantee(post.sv_currentFanState, post.sv_currentSetPoint, post.sv_fanError, post.sv_latestTemp),
    control::compute_spec_TC_Req_02_guarantee(post.sv_currentFanState, post.sv_currentSetPoint, post.sv_fanError, post.sv_latestTemp),
    control::compute_spec_TC_Req_03_guarantee(pre.sv_currentFanState, post.sv_currentFanState, post.sv_currentSetPoint, post.sv_fanError, post.sv_latestTemp),
    control::compute_spec_mustSendFanCmd_guarantee(pre.sv_currentFanState, post.sv_currentFanState, post.sv_fanError, post.fanCmd),
    control::compute_spec_setPointChanged_guarantee(post.sv_currentSetPoint, pre.setPoint),
    control::compute_spec_fanAck_setPointNotModified_guarantee(pre.sv_currentSetPoint, post.sv_currentSetPoint, pre.fanAck, pre.setPoint),
    control::compute_spec_currentTemp_setPointNotModified_guarantee(pre.sv_currentSetPoint, post.sv_currentSetPoint, pre.sensedTemp, pre.setPoint),
    control::compute_spec_tempChanged_guarantee(post.sv_latestTemp, pre.sensedTemp),
    control::compute_spec_setPoint_latestTempNotModified_guarantee(pre.sv_latestTemp, post.sv_latestTemp, pre.sensedTemp, pre.setPoint),
    control::compute_spec_fanAck_latestTempNotModified_guarantee(pre.sv_latestTemp, post.sv_latestTemp, pre.sensedTemp, pre.fanAck),
    control::compute_spec_manageErrorState_guarantee(post.sv_fanError, pre.fanAck),
    control::integration_spec_currentTempRange_assume(pre.sensedTemp),
  ensures
    sys_assert_tc_req_01_after_control(post),
{}

/** VC[5]: Pre-Assert -- after_control |- FAN compute assumes */
pub proof fn vc_pre_assert_fan(st: SystemState)
  requires
    sys_assert_tc_req_01_after_control(st),
  ensures
    true /* no assertions at out-places */,
{}

/** VC[6]: Next-Assert (task) -- after_control + frames + FAN postcondition |- after_fan */
pub proof fn vc_next_assert_task_fan(pre: SystemState, post: SystemState)
  requires
    sys_assert_tc_req_01_after_control(pre),
    fan_local_write_frame(pre, post),
    fan_global_write_frame(pre, post),
  ensures
    sys_assert_tc_req_01_after_fan(post),
{}

/** VC[7]: Next-Assert (control point) -- after_fan |- END (state unchanged) */
pub proof fn vc_next_assert_skip_t3(st: SystemState)
  requires
    sys_assert_tc_req_01_after_fan(st),
  ensures
    sys_assert_tc_req_01_END(st),
{}

} // verus!
